// ==================================================
//  pages/Designs.jsx — عرض التصاميم + التقييم
// ==================================================
import React, { useState, useEffect } from 'react'
import { getDesigns } from '../services/designService'

export default function Designs() {
  const [designs, setDesigns]   = useState([])
  const [loading, setLoading]   = useState(true)
  const [ratings, setRatings]   = useState({})   // تقييمات محلية
  const [filter, setFilter]     = useState('all')

  useEffect(() => {
    fetchDesigns()
  }, [])

  const fetchDesigns = async () => {
    try {
      const data = await getDesigns()
      setDesigns(data)
    } catch {
      // إذا الـ Backend غير شغال، نعرض بيانات تجريبية
      setDesigns(SAMPLE_DESIGNS)
    } finally {
      setLoading(false)
    }
  }

  const handleRate = (designId, star) => {
    setRatings(prev => ({ ...prev, [designId]: star }))
  }

  if (loading) return <div className="page-center"><div className="spinner" /></div>

  return (
    <div style={styles.page}>
      {/* Header */}
      <div style={styles.header}>
        <h1 style={styles.title}>معرض التصاميم</h1>
        <p style={styles.sub}>اكتشف تصاميم فريدة صُنعت بالذكاء الاصطناعي</p>

        {/* فلتر */}
        <div style={styles.filters}>
          {['all', 'فساتين', 'قمصان', 'بناطيل', 'عبايات'].map(f => (
            <button
              key={f}
              onClick={() => setFilter(f)}
              className="btn"
              style={{
                ...styles.filterBtn,
                background: filter === f ? '#0a0a0a' : '#fff',
                color:      filter === f ? '#fff'    : '#333',
              }}
            >
              {f === 'all' ? 'الكل' : f}
            </button>
          ))}
        </div>
      </div>

      {/* شبكة التصاميم */}
      <div style={styles.grid}>
        {designs.map(design => (
          <DesignCard
            key={design.id}
            design={design}
            userRating={ratings[design.id] || 0}
            onRate={(star) => handleRate(design.id, star)}
          />
        ))}
      </div>

      {designs.length === 0 && (
        <div style={styles.empty}>
          <span style={{fontSize: 60}}>👗</span>
          <p>لا توجد تصاميم بعد</p>
        </div>
      )}
    </div>
  )
}

// ===== كارد التصميم =====
function DesignCard({ design, userRating, onRate }) {
  const [liked, setLiked] = useState(false)
  const [showOrder, setShowOrder] = useState(false)

  return (
    <div style={styles.card}>
      {/* صورة التصميم */}
      <div style={styles.imageBox}>
        {design.image ? (
          <img src={design.image} alt={design.title} style={styles.image} />
        ) : (
          <div style={styles.imagePlaceholder}>
            <span style={{fontSize: 60}}>👗</span>
          </div>
        )}
        {/* زر الإعجاب */}
        <button
          onClick={() => setLiked(!liked)}
          style={{ ...styles.likeBtn, color: liked ? '#e74c3c' : '#999' }}
        >
          {liked ? '❤️' : '🤍'}
        </button>
      </div>

      {/* معلومات */}
      <div style={styles.info}>
        <h3 style={styles.designTitle}>{design.title}</h3>
        <p style={styles.designDesc}>{design.description}</p>

        {/* التقييم بالنجوم */}
        <div style={styles.stars}>
          <span style={styles.starsLabel}>تقييمك:</span>
          {[1,2,3,4,5].map(star => (
            <button
              key={star}
              onClick={() => onRate(star)}
              style={{ background: 'none', border: 'none', cursor: 'pointer', fontSize: 20, padding: '0 2px' }}
            >
              {star <= userRating ? '⭐' : '☆'}
            </button>
          ))}
        </div>

        {/* السعر والطلب */}
        <div style={styles.bottom}>
          <span style={styles.price}>{design.price} ر.س</span>
          <button
            onClick={() => setShowOrder(true)}
            className="btn btn-primary"
            style={{ padding: '8px 20px', fontSize: 13 }}
          >
            اطلب الآن
          </button>
        </div>
      </div>

      {/* نافذة الطلب */}
      {showOrder && (
        <OrderModal design={design} onClose={() => setShowOrder(false)} />
      )}
    </div>
  )
}

// ===== نافذة الطلب =====
function OrderModal({ design, onClose }) {
  const [address, setAddress]   = useState('')
  const [quantity, setQuantity] = useState(1)
  const [done, setDone]         = useState(false)

  const submit = () => {
    if (!address) return alert('أدخل عنوان التوصيل')
    // هنا تستدعي orderService.createOrder(...)
    setDone(true)
  }

  return (
    <div style={styles.overlay}>
      <div style={styles.modal}>
        {done ? (
          <div style={{textAlign:'center', padding: 20}}>
            <p style={{fontSize: 50}}>✅</p>
            <h3 style={{fontFamily:"'Playfair Display',serif", fontSize: 24, margin: '16px 0 8px'}}>تم الطلب!</h3>
            <p style={{color:'#888', marginBottom: 24}}>سنتواصل معك قريباً</p>
            <button onClick={onClose} className="btn btn-primary">إغلاق</button>
          </div>
        ) : (
          <>
            <h3 style={styles.modalTitle}>طلب: {design.title}</h3>
            <div style={styles.field}>
              <label style={styles.label}>الكمية</label>
              <input
                type="number" min="1" max="10"
                value={quantity}
                onChange={e => setQuantity(e.target.value)}
                className="input"
              />
            </div>
            <div style={styles.field}>
              <label style={styles.label}>عنوان التوصيل</label>
              <textarea
                value={address}
                onChange={e => setAddress(e.target.value)}
                placeholder="المدينة، الحي، الشارع..."
                className="input"
                rows={3}
                style={{resize:'none'}}
              />
            </div>
            <p style={{color:'#c9a84c', fontWeight:600, marginBottom:16}}>
              الإجمالي: {design.price * quantity} ر.س
            </p>
            <div style={{display:'flex', gap:10}}>
              <button onClick={submit}  className="btn btn-primary" style={{flex:1}}>تأكيد الطلب</button>
              <button onClick={onClose} className="btn btn-outline" style={{flex:1}}>إلغاء</button>
            </div>
          </>
        )}
      </div>
    </div>
  )
}

// بيانات تجريبية تظهر إذا Backend غير شغال
const SAMPLE_DESIGNS = [
  { id:1, title:'فستان سهرة ذهبي',   description:'تصميم أنيق للمناسبات', price:450, image:null },
  { id:2, title:'عباءة كلاسيكية',     description:'عباءة فاخرة بتطريز يدوي', price:380, image:null },
  { id:3, title:'قميص كاجوال',        description:'قميص عصري للاستخدام اليومي', price:120, image:null },
  { id:4, title:'فستان صيفي',         description:'فستان خفيف ومريح', price:200, image:null },
]

const styles = {
  page:       { padding: '48px 60px', maxWidth: 1200, margin: '0 auto' },
  header:     { textAlign: 'center', marginBottom: 48 },
  title:      { fontFamily: "'Playfair Display',serif", fontSize: 42, marginBottom: 12 },
  sub:        { color: '#888', fontSize: 16, marginBottom: 28 },
  filters:    { display: 'flex', gap: 10, justifyContent: 'center', flexWrap: 'wrap' },
  filterBtn:  { padding: '8px 22px', borderRadius: 50, border: '1.5px solid #ddd', cursor: 'pointer', fontSize: 14 },
  grid:       { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: 28 },
  card:       { background: '#fff', borderRadius: 20, overflow: 'hidden', boxShadow: '0 4px 20px rgba(0,0,0,0.07)', position: 'relative' },
  imageBox:   { position: 'relative', height: 260, background: '#f5f0e8' },
  image:      { width: '100%', height: '100%', objectFit: 'cover' },
  imagePlaceholder: { height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center' },
  likeBtn:    { position: 'absolute', top: 12, right: 12, background: '#fff', border: 'none', borderRadius: '50%', width: 36, height: 36, cursor: 'pointer', fontSize: 18, boxShadow: '0 2px 8px rgba(0,0,0,0.1)' },
  info:       { padding: '20px 20px 16px' },
  designTitle:{ fontFamily: "'Playfair Display',serif", fontSize: 18, marginBottom: 6 },
  designDesc: { color: '#888', fontSize: 13, marginBottom: 12, lineHeight: 1.5 },
  stars:      { display: 'flex', alignItems: 'center', gap: 4, marginBottom: 14 },
  starsLabel: { fontSize: 13, color: '#888', marginLeft: 4 },
  bottom:     { display: 'flex', justifyContent: 'space-between', alignItems: 'center' },
  price:      { fontFamily: "'Playfair Display',serif", fontSize: 20, fontWeight: 700, color: '#c9a84c' },
  empty:      { textAlign: 'center', padding: '80px 0', color: '#aaa' },
  overlay:    { position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 200 },
  modal:      { background: '#fff', borderRadius: 20, padding: 36, width: '90%', maxWidth: 420 },
  modalTitle: { fontFamily: "'Playfair Display',serif", fontSize: 22, marginBottom: 24 },
  field:      { marginBottom: 16 },
  label:      { display: 'block', marginBottom: 6, fontSize: 14, fontWeight: 500 },
}
